import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './GenerateInvoice.css';

const GenerateInvoice = () => {
    const [customers, setCustomers] = useState([]);
    const [selectedCustomer, setSelectedCustomer] = useState('');
    const [products, setProducts] = useState([]);
    const [selectedProducts, setSelectedProducts] = useState([]);
    const [vat, setVat] = useState(7.5);
    const [totalAmount, setTotalAmount] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchCustomers = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/customers');
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const data = await response.json();
                setCustomers(data);
            } catch (error) {
                console.error('Error fetching customers:', error);
            }
        };

        const fetchProducts = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/products');
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const data = await response.json();
                setProducts(data);
            } catch (error) {
                console.error('Error fetching products:', error);
            }
        };

        fetchCustomers();
        fetchProducts();
    }, []);

    const handleAddProduct = () => {
        setSelectedProducts([...selectedProducts, { product: '', quantity: 0 }]);
    };

    const handleProductChange = (index, field, value) => {
        const updatedProducts = [...selectedProducts];
        if (field === 'product') {
            const selectedProduct = products.find(p => p.id === parseInt(value));
            updatedProducts[index][field] = selectedProduct || '';
        } else {
            updatedProducts[index][field] = value;
        }
        setSelectedProducts(updatedProducts);
        calculateTotal(updatedProducts);
    };

    const calculateTotal = (products) => {
        const subtotal = products.reduce((sum, item) => sum + (item.quantity * (item.product?.price || 0)), 0);
        const total = subtotal + (subtotal * vat / 100);
        setTotalAmount(total);
    };

    const handleSubmit = (status) => {
        // Submit invoice logic here
        console.log('Invoice submitted as:', status);
    };

    return (
        <div className="generate-invoice-container">
            <h1>Generate Invoice</h1>
            <div className="company-details">
                <h2>Bonnesante Medicals</h2>
                <p>Head Office: No 17A Isuofia/6B Peace Avenue, Federal Housing TransEkulu</p>
                <p>Bank Name: MONIEPOINT</p>
                <p>Account Name: BONNESANTE MEDICALS</p>
                <p>Account Number: 8259518195</p>
                <p>Bank Name: Access Bank</p>
                <p>Account Name: BONNESANTE MEDICALS</p>
                <p>Account Number: 1379643548</p>
            </div>
            <form>
                <label>
                    Customer:
                    <select
                        value={selectedCustomer}
                        onChange={(e) => setSelectedCustomer(e.target.value)}
                        required
                    >
                        <option value="">Select a customer</option>
                        {customers.map((customer) => (
                            <option key={customer.id} value={customer.id}>{customer.name}</option>
                        ))}
                    </select>
                </label>
                <p>
                    <a href="#" onClick={() => navigate('/register-customer')}>
                        Register a new customer
                    </a>
                </p>
                <div className="product-list">
                    {selectedProducts.map((item, index) => (
                        <div key={index} className="product-item">
                            <select
                                value={item.product?.id || ''}
                                onChange={(e) => handleProductChange(index, 'product', e.target.value)}
                            >
                                <option value="">Select Product</option>
                                {products.map((product) => (
                                    <option key={product.id} value={product.id}>{product.name}</option>
                                ))}
                            </select>
                            <input
                                type="number"
                                value={item.quantity}
                                onChange={(e) => handleProductChange(index, 'quantity', parseInt(e.target.value) || 0)}
                                placeholder="Quantity"
                            />
                        </div>
                    ))}
                    <button type="button" onClick={handleAddProduct}>Add Product</button>
                </div>
                <p>VAT: {vat}%</p>
                <p>Total Amount: {totalAmount.toFixed(2)}</p>
                <button type="button" onClick={() => handleSubmit('unpaid')}>Submit as Unpaid</button>
                <button type="button" onClick={() => handleSubmit('paid')}>Submit as Paid</button>
            </form>
        </div>
    );
};

export default GenerateInvoice;
